mapper.insert:
insert into stock_rt_info
( id, stock_code, cur_time
, stock_name, open_price, pre_close_price
, cur_price, max_price, min_price
, trade_amount, trade_volume)
values ( #{id,jdbcType=VARCHAR}, #{stockCode,jdbcType=CHAR}, #{curTime,jdbcType=TIMESTAMP}
       , #{stockName,jdbcType=VARCHAR}, #{openPrice,jdbcType=DECIMAL}, #{preClosePrice,jdbcType=DECIMAL}
       , #{curPrice,jdbcType=DECIMAL}, #{maxPrice,jdbcType=DECIMAL}, #{minPrice,jdbcType=DECIMAL}
       , #{tradeAmount,jdbcType=BIGINT}, #{tradeVolume,jdbcType=DECIMAL})

mapper.select:
select date_format(tmp.cur_time,'%Y%m%d%H%i') as time, count(*) as count from (select sri.cur_time, (sri.cur_price-sri.pre_close_price)/sri.pre_close_price as increase from stock_rt_info as sri where sri.cur_time between #{startTime} and #{endTime}
having increase >=0.1
having increase <=-0.1
) as tmp group by tmp.cur_time order by tmp.cur_time asc

select max(sri.cur_time) as closeDate
from stock_rt_info as sri
where sri.stock_code = #{code}
  and sri.cur_time between #{startTime} and #{endTime}
group by date_format(sri.cur_time, '%Y%m%d')

SELECT cur_price
FROM stock_rt_info
WHERE cur_time = #{closeDateStr}
  AND stock_code = ${code}

SELECT open_price
FROM stock_rt_info
WHERE cur_time = #{openDate}
  AND stock_code = ${code}
GROUP BY open_price
